void solve(int CASE)
{
	ll n; cin >> n;
	var V = vector<ll>(n + 1);
	var L = vector<ll>(n + 1);
	fa(i, 1, n)cin >> V[i];
	fa(i, 1, n)cin >> L[i];

	sort(all1(V), greater<>());
	sort(all1(L));
	var prev = vector<__int128>(n + 1);
	var prel = vector<__int128>(n + 1);
	fa(i, 1, n) {
		prev[i] = prev[i - 1] + V[i];
		prel[i] = prel[i - 1] + L[i];
	}

	int q; cin >> q;
	while (q--) {
		ll t; cin >> t;

		var f = [&](__int128 k)->__int128 {
			return prev[k] - prel[k] * t;
			};
		ll l = 1, r = n - 1;
		while (l < r) {
			ll mid = l + r >> 1;
			if (f(mid) < f(mid + 1))l = mid + 1;
			else r = mid;
		}

		ll ans = max({ (__int128)0, prev[l] - prel[l] * t, prev[n] - prel[n] * t });
		cout << ans << ' ';
	}cout << endl;
	return;
}
